// Script Continued Below
// RAJ - STRY 0011909 - changed from firing on process definition to firing on Tasker Definition.
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	if (oldValue != "" && oldValue != newValue){
		if (g_scratchpad.calchaschildren>0){
			g_form.addInfoMessage(getMessage('Tasker - Changing the Primary Office Updates All Descendant Tasks'));
		}
	}

}
